## 4. 读写工具

新增文件: `cli-core/src/core/package/index.ts`

```typescript
// ── 读取 ──
export type ReadPackageParams = {
  base: string;  // 项目根目录 或 home 目录
  scope: 'project' | 'global';
  home: string;
};

const readPackage = ({ base, scope, home }: ReadPackageParams): AiPackage => {
  const filePath = scope === 'global'
    ? join(home, '.ai-labs', 'ai-package.json')
    : join(base, 'ai-package.json');

  if (!existsSync(filePath)) return createEmpty();

  const raw = JSON.parse(readFileSync(filePath, 'utf-8'));
  return validateAndMigrate(raw);
};

// ── 写入 ──
const writePackage = ({ base, scope, home }: ReadPackageParams, pkg: AiPackage): void => {
  const filePath = scope === 'global'
    ? join(home, '.ai-labs', 'ai-package.json')
    : join(base, 'ai-package.json');

  ensureDirSync(dirname(filePath));
  writeFileSync(filePath, JSON.stringify(pkg, null, 2) + '\n');
};

// ── 空文档 ──
const createEmpty = (): AiPackage => ({
  version: 1,
  plugins: {},
  components: {
    skills: {},
    mcp: {},
    rules: {},
    subagents: {},
    hooks: {},
    commands: {},
  },
});

// ── 添加单组件记录 ──
export type AddComponentEntryParams = {
  pkg: AiPackage;
  componentType: ComponentType;
  slug: string;
  entry: ComponentEntry;
};

const addComponentEntry = ({ pkg, componentType, slug, entry }: AddComponentEntryParams): AiPackage => ({
  ...pkg,
  components: {
    ...pkg.components,
    [componentType]: {
      ...pkg.components[componentType],
      [slug]: entry,
    },
  },
});

// ── 移除单组件记录 ──
const removeComponentEntry = (
  pkg: AiPackage,
  componentType: ComponentType,
  slug: string,
): AiPackage => {
  const updated = { ...pkg.components[componentType] };
  delete updated[slug];
  return {
    ...pkg,
    components: { ...pkg.components, [componentType]: updated },
  };
};

// ── 添加 Plugin 记录 ──
const addPluginEntry = (pkg: AiPackage, slug: string, entry: PluginEntry): AiPackage => ({
  ...pkg,
  plugins: { ...pkg.plugins, [slug]: entry },
});

// ── 移除 Plugin 记录 ──
const removePluginEntry = (pkg: AiPackage, slug: string): AiPackage => {
  const updated = { ...pkg.plugins };
  delete updated[slug];
  return { ...pkg, plugins: updated };
};

// ── 查询：某文件是否被其他 entry 引用 ──
const isFileReferencedElsewhere = (
  pkg: AiPackage,
  filePath: string,
  excludeSlug: string,
): boolean => {
  // 检查 plugins
  for (const [slug, entry] of Object.entries(pkg.plugins)) {
    if (slug === excludeSlug) continue;
    const allFiles = [
      ...entry.skills, ...entry.rules, ...entry.subagents,
      ...entry.commands, ...entry.hooks, ...entry.mcp,
    ];
    if (allFiles.includes(filePath)) return true;
  }
  // 检查 components
  for (const typeEntries of Object.values(pkg.components)) {
    for (const [slug, entry] of Object.entries(typeEntries)) {
      if (slug === excludeSlug) continue;
      if (entry.files?.includes(filePath)) return true;
    }
  }
  return false;
};
```

---

## 5. 冲突与边界情况

| 场景 | 处理策略 |
|------|----------|
| 同一组件被 Plugin 和单独安装都引用 | remove 时检查 `isFileReferencedElsewhere`，有其他引用则只删追踪记录不删文件 |
| `mergedKeys` 中的 key 被用户手动改名 | remove 时 verify key 存在，不存在则 warn 并跳过 |
| `ai-package.json` 与磁盘不同步 | 本次不处理，TODO: `ai-labs doctor` 命令 |
| 多人协作 Git 合并冲突 | JSON 结构扁平，冲突概率低。后续可考虑排序 key |

# CLI 安装/卸载逻辑

> 涉及目录: `cli-core/src/core/marketplace/`, `cli/src/command/*/`

---

## 1. Download Client

新增文件: `cli-core/src/core/marketplace/api.ts`

```typescript
import { request } from '@/core/api';

export type DownloadComponentParams = {
  type: ComponentType;
  slug: string;
  owner?: string;
  version?: string;
};

export type DownloadComponentResult =
  | { ok: true; zipBuffer: ArrayBuffer; }
  | { ok: false; reason: string };

// 下载单组件 zip
const downloadComponent = async ({
  type, slug, owner, version,
}: DownloadComponentParams): Promise<DownloadComponentResult> => {
  const apiPath = `/api/marketplace/${type}/download`;
  const body = { slug, owner, version };

  const res = await fetch(`${getBaseUrl()}${apiPath}`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json', ...getAuthHeaders() },
    body: JSON.stringify(body),
  });

  if (!res.ok) {
    const err = await res.json().catch(() => ({}));
    return { ok: false, reason: err?.error?.message ?? `HTTP ${res.status}` };
  }

  const zipBuffer = await res.arrayBuffer();
  return { ok: true, zipBuffer };
};

// 下载 Plugin zip
const downloadPlugin = async (slug: string, version?: string) => {
  return downloadComponent({ type: 'plugin' as any, slug, version });
};
```

---

## 2. Zip 解压

```typescript
import JSZip from 'jszip';

export type UnzippedFile = {
  path: string;
  content: string;
};

const unzipBuffer = async (buffer: ArrayBuffer): Promise<Array<UnzippedFile>> => {
  const zip = await JSZip.loadAsync(buffer);
  const files: Array<UnzippedFile> = [];

  for (const [path, zipEntry] of Object.entries(zip.files)) {
    if (zipEntry.dir) continue;
    const content = await zipEntry.async('string');
    files.push({ path, content });
  }

  return files;
};
```

---

## 3. 安装分发器

新增文件: `cli-core/src/core/marketplace/install.ts`

每种类型的安装逻辑:

```typescript
// ── 文件类型（rules, subagents, commands）──
// 直接写入单个文件
export type InstallFileParams = {
  content: string;
  slug: string;
  targetDir: string;    // 例如 .cursor/rules
  extension: string;    // 例如 .mdc
};

const installFile = ({ content, slug, targetDir, extension }: InstallFileParams): string => {
  ensureDirSync(targetDir);
  const filePath = join(targetDir, `${slug}${extension}`);
  writeFileSync(filePath, content);
  return filePath; // 返回写入路径，供 ai-package.json 记录
};

// ── 合并类型（mcp）──
export type InstallMcpParams = {
  installConfig: Record<string, unknown>;  // 要合并到 mcpServers 的配置
  targetPath: string;                       // 例如 .cursor/mcp.json
  force?: boolean;
};

export type InstallMcpResult = {
  mergedKeys: Array<string>;
  action: 'added' | 'replaced' | 'skipped';
};

const installMcp = ({ installConfig, targetPath, force }: InstallMcpParams): InstallMcpResult => {
  ensureDirSync(dirname(targetPath));

  const existing = existsSync(targetPath)
    ? JSON.parse(readFileSync(targetPath, 'utf-8'))
    : { mcpServers: {} };

  existing.mcpServers ??= {};
  const mergedKeys: Array<string> = [];

  for (const [name, config] of Object.entries(installConfig)) {
    if (existing.mcpServers[name] && !force) {
      continue; // skip, CLI 层会交互询问
    }
    existing.mcpServers[name] = config;
    mergedKeys.push(name);
  }

  writeFileSync(targetPath, JSON.stringify(existing, null, 2) + '\n');
  return { mergedKeys, action: mergedKeys.length > 0 ? 'added' : 'skipped' };
};

// ── 合并类型（hooks）──
export type InstallHooksParams = {
  hookFiles: Array<UnzippedFile>;  // hooks.json + 脚本文件
  targetPath: string;               // 例如 .cursor/hooks.json
  targetDir: string;                 // 例如 .cursor/hooks/
};

const installHooks = ({ hookFiles, targetPath, targetDir }: InstallHooksParams): {
  mergedKeys: Array<string>;
  files: Array<string>;
} => {
  // 1. 找到 hooks.json
  const hooksJsonFile = hookFiles.find(f => f.path.endsWith('hooks.json'));
  if (!hooksJsonFile) return { mergedKeys: [], files: [] };

  const newHooks = JSON.parse(hooksJsonFile.content);
  const files: Array<string> = [];

  // 2. 写入脚本文件到 targetDir
  for (const file of hookFiles) {
    if (file.path.endsWith('hooks.json')) continue;
    const scriptPath = join(targetDir, basename(file.path));
    ensureDirSync(dirname(scriptPath));
    writeFileSync(scriptPath, file.content);
    files.push(scriptPath);
  }

  // 3. 合并 hooks.json
  ensureDirSync(dirname(targetPath));
  const existing = existsSync(targetPath)
    ? JSON.parse(readFileSync(targetPath, 'utf-8'))
    : {};

  const mergedKeys: Array<string> = [];

  // hooks 按 event 名合并，同 event 下按 command 去重
  for (const [event, handlers] of Object.entries(newHooks.hooks ?? {})) {
    existing.hooks ??= {};
    existing.hooks[event] ??= [];
    for (const handler of handlers as Array<unknown>) {
      const h = handler as { command?: string };
      const isDup = existing.hooks[event].some(
        (e: { command?: string }) => e.command === h.command
      );
