// ── 读取 ──
export type ReadPackageParams = {
  base: string;  // 项目根目录 或 home 目录
  scope: 'project' | 'global';
  home: string;
};

const readPackage = ({ base, scope, home }: ReadPackageParams): AiPackage => {
  const filePath = scope === 'global'
    ? join(home, '.ai-labs', 'ai-package.json')
    : join(base, 'ai-package.json');

  if (!existsSync(filePath)) return createEmpty();

  const raw = JSON.parse(readFileSync(filePath, 'utf-8'));
  return validateAndMigrate(raw);
};

// ── 写入 ──
const writePackage = ({ base, scope, home }: ReadPackageParams, pkg: AiPackage): void => {
  const filePath = scope === 'global'
    ? join(home, '.ai-labs', 'ai-package.json')
    : join(base, 'ai-package.json');

  ensureDirSync(dirname(filePath));
  writeFileSync(filePath, JSON.stringify(pkg, null, 2) + '\n');
};

// ── 空文档 ──
const createEmpty = (): AiPackage => ({
  version: 1,
  plugins: {},
  components: {
    skills: {},
    mcp: {},
    rules: {},
    subagents: {},
    hooks: {},
    commands: {},
  },
});

// ── 添加单组件记录 ──
export type AddComponentEntryParams = {
  pkg: AiPackage;
  componentType: ComponentType;
  slug: string;
  entry: ComponentEntry;
};

const addComponentEntry = ({ pkg, componentType, slug, entry }: AddComponentEntryParams): AiPackage => ({
  ...pkg,
  components: {
    ...pkg.components,
    [componentType]: {
      ...pkg.components[componentType],
      [slug]: entry,
    },
  },
});

// ── 移除单组件记录 ──
const removeComponentEntry = (
  pkg: AiPackage,
  componentType: ComponentType,
  slug: string,
): AiPackage => {
  const updated = { ...pkg.components[componentType] };
  delete updated[slug];
  return {
    ...pkg,
    components: { ...pkg.components, [componentType]: updated },
  };
};

// ── 添加 Plugin 记录 ──
const addPluginEntry = (pkg: AiPackage, slug: string, entry: PluginEntry): AiPackage => ({
  ...pkg,
  plugins: { ...pkg.plugins, [slug]: entry },
});

// ── 移除 Plugin 记录 ──
const removePluginEntry = (pkg: AiPackage, slug: string): AiPackage => {
  const updated = { ...pkg.plugins };
  delete updated[slug];
  return { ...pkg, plugins: updated };
};

// ── 查询：某文件是否被其他 entry 引用 ──
const isFileReferencedElsewhere = (
  pkg: AiPackage,
  filePath: string,
  excludeSlug: string,
): boolean => {
  // 检查 plugins
  for (const [slug, entry] of Object.entries(pkg.plugins)) {
    if (slug === excludeSlug) continue;
    const allFiles = [
      ...entry.skills, ...entry.rules, ...entry.subagents,
      ...entry.commands, ...entry.hooks, ...entry.mcp,
    ];
    if (allFiles.includes(filePath)) return true;
  }
  // 检查 components
  for (const typeEntries of Object.values(pkg.components)) {
    for (const [slug, entry] of Object.entries(typeEntries)) {
      if (slug === excludeSlug) continue;
      if (entry.files?.includes(filePath)) return true;
    }
  }
  return false;
};
