export type InstallMcpResult = {
  mergedKeys: Array<string>;
  action: 'added' | 'replaced' | 'skipped';
};

const installMcp = ({ installConfig, targetPath, force }: InstallMcpParams): InstallMcpResult => {
  ensureDirSync(dirname(targetPath));

