async function checkSkillAudit(skillName: string, entry: AiJsonGitTrackedEntry): Promise<boolean> {
  if (entry.source !== 'github') return true;

  dim(t('audit.checking', { r: { name: skillName } }));

  try {
    const result = await apiCli_Audit({
      type: 'skill',
      source: entry.source,
      owner: entry.owner,
      repo: entry.repo,
      name: skillName,
      version: entry.version,
      gitPath: entry.gitPath,
    });

    if (!result.success) {
