  if (agentResult.needsInteraction && !agentResult.skipInteraction) {
    const defaultSelectedNames = new Set(agentResult.defaultSelected.map((a) => a.name));
    const chosen = await select<string>({
      message: t('skill.add.selectAgents'),
      options: agentResult.agents.map((a) => ({
