/**
 * Check Argus security audit before installation (non-interactive).
 * Returns true if installation should proceed, false if blocked.
 */
async function checkSkillAuditPure(
  skillName: string,
  entry: AiJsonGitTrackedEntry
): Promise<boolean> {
  if (entry.source !== 'github') return true;

  console.log(t('audit.checking', { r: { name: skillName } }));

  try {
    const result = await apiCli_Audit({
      type: 'skill',
      source: entry.source,
      owner: entry.owner,
      repo: entry.repo,
      name: skillName,
      version: entry.version,
      gitPath: entry.gitPath,
    });

    if (!result.success) {
      console.error(t('audit.checkFailed', { r: { name: skillName } }));
      return true;
    }

    const { argus } = result.data;

    if (argus.poisoned) {
      console.error(t('audit.poisoned', { r: { name: skillName } }));
      return false;
    }

    if (argus.score === 0) {
      console.error(t('audit.notAudited', { r: { name: skillName } }));
      return true;
    }

    if (argus.score >= 7) {
      console.error(t('audit.highRisk', { r: { name: skillName, score: String(argus.score) } }));
      return false;
    }

    console.log(t('audit.safe', { r: { name: skillName, score: String(argus.score) } }));
    return true;
  } catch {
    console.error(t('audit.checkFailed', { r: { name: skillName } }));
    return true;
  }
}

