import { AI_JSON_VERSION, TRACKED_SOURCES } from '@/const';
import { getEnv } from '@/core/config';

/**
 * Resolve the $schema URL for ai-package.json, based on the current web_url config.
 */
export const getAiJsonSchemaUrl = (): string => {
  const webUrl = (getEnv({ key: 'webUrl' }) || 'https://ai-skills.bytedance.net').replace(
    /\/+$/,
    ''
  );
  return `${webUrl}/aijson/${AI_JSON_VERSION}/schema.json`;
};

export type BuildAiJsonSchemaParams = {
  /** Schema version, defaults to AI_JSON_VERSION */
  version?: string;
  /** Base URL for $id, defaults to https://ai-skills.bytedance.net */
  baseUrl?: string;
};

const buildAiJsonSchema = (params?: BuildAiJsonSchemaParams): Record<string, unknown> => {
  const version = params?.version ?? AI_JSON_VERSION;
  const baseUrl = (params?.baseUrl ?? 'https://ai-skills.bytedance.net').replace(/\/+$/, '');

  const trackedSourceEnum = [...TRACKED_SOURCES];

  /* ── Reusable $defs ───────────────────────────────── */

  const gitTrackedEntry = {
    type: 'object',
    description:
      'Git-tracked entry from github/codebase/local/team/workspace sources. ' +
      'Version is pinned via "sha@<hex>" (github/codebase) or semver (local/team/workspace). ' +
      'gitPath disambiguates same-name items within the same repo.',
    required: ['source', 'owner', 'repo', 'version', 'gitPath'],
    properties: {
      source: {
        type: 'string',
        enum: trackedSourceEnum,
        description: 'Tracked distribution source type.',
      },
      owner: { type: 'string', description: 'Repository owner or organization.' },
      repo: { type: 'string', description: 'Repository name (or collection name).' },
      version: {
        type: 'string',
        description: 'Version identifier — "sha@<hex>" for github/codebase, semver for local/team.',
        examples: ['sha@abcd1234ef567890abcd1234ef567890abcd1234', '1.0.0'],
      },
      gitPath: {
        type: 'string',
        description:
          'Path relative to the repository root. Empty string: resolve at install via SKILL.md discovery using the manifest skill key.',
      },
      branch: {
        type: 'string',
        description: 'Branch or tag; omitted when installed from the default branch.',
      },
    },
    additionalProperties: false,
  };

  const originEntry = {
    type: 'object',
    description:
      'Project-original content — not version-tracked. Optional path: project-relative or absolute; used to reinstall from disk.',
    required: ['source'],
    properties: {
      source: { type: 'string', const: 'origin' },
      path: {
        type: 'string',
        description:
          'Directory or .zip containing the skill/plugin; project-relative to ai-package.json parent, or absolute (e.g. global installs).',
      },
    },
    additionalProperties: false,
  };

  /* ── Discriminated union definitions ────────────── */

  const pluginEntry = {
    description: 'Plugin entry — git-tracked or project-original.',
    oneOf: [{ $ref: '#/$defs/gitTrackedEntry' }, { $ref: '#/$defs/originEntry' }],
  };

  const skillEntry = {
    description: 'Skill entry — git-tracked or project-original.',
    oneOf: [{ $ref: '#/$defs/gitTrackedEntry' }, { $ref: '#/$defs/originEntry' }],
  };

  const mcpEntry = {
    description: 'MCP entry — git-tracked or project-original.',
    oneOf: [{ $ref: '#/$defs/gitTrackedEntry' }, { $ref: '#/$defs/originEntry' }],
  };

  /* ── Root schema ──────────────────────────────────── */

  return {
    $schema: 'http://json-schema.org/draft-07/schema#',
    $id: `${baseUrl}/aijson/${version}/schema.json`,
    title: 'ai-package.json',
    description:
      'AI Skills CLI project manifest — tracks installed skills, MCPs, and plugins with source provenance.',
    type: 'object',
    properties: {
      $schema: {
        type: 'string',
        description: 'Optional JSON Schema URL for editor validation (CLI does not write this).',
      },
      name: {
        type: 'string',
        description: 'Project name.',
      },
      registry: {
        type: 'string',
        description:
          'Optional; defaults to CLI web_url / SKILL_HUB. Omitted from disk — resolved at read time.',
      },
      plugin: {
        type: 'object',
        description: 'Installed plugins (keyed by plugin name).',
        additionalProperties: { $ref: '#/$defs/pluginEntry' },
      },
      skill: {
        type: 'object',
        description: 'Installed standalone skills (keyed by skill name).',
        additionalProperties: { $ref: '#/$defs/skillEntry' },
      },
      mcp: {
        type: 'object',
        description: 'Installed standalone MCPs (keyed by MCP name).',
        additionalProperties: { $ref: '#/$defs/mcpEntry' },
      },
    },
    additionalProperties: false,
    $defs: {
      gitTrackedEntry,
      originEntry,
      pluginEntry,
      skillEntry,
      mcpEntry,
    },
  };
};

export type BuildAiJsonSchema = typeof buildAiJsonSchema;

export default buildAiJsonSchema;

