import JSZip from 'jszip';
import { downloadZip } from '@/core/api';
import { cloneAndRead, discoverSkillPath, fetchGitSingleFile, resolveToken } from '@/core/git';
import { isShaVersionString } from '@/core/registry/pickLatestVersion';
import { vlog } from '@/core/verbose';
import type { AiJsonFile, AiJsonSource } from '@/types';
import { ResourceType, SourceGit, SourceRegistry } from '@/types';

export type ResolveSourceParams = {
  source: AiJsonSource;
  owner: string;
  repo: string;
  version: string;
  gitPath: string;
  token?: string;
  /** Skill/MCP resource name when gitPath is "." or uninformative (registry zip). */
  resourceName?: string;
};

export type ResolveSourceResult = {
  success: boolean;
  files?: AiJsonFile[];
  error?: string;
};

const extractSha = (version: string): string => {
  if (version.startsWith('sha@')) return version.slice(4);
  return version;
};

const isFilePath = (p: string): boolean => {
  const last = p.split('/').pop() ?? '';
  return last.includes('.');
};

const resolveTokenForSource = (params: ResolveSourceParams): string | undefined =>
  resolveToken(params.token, params.source === SourceGit.Codebase ? 'codebase' : 'github');

/**
 * 与 skill add 的 resolveGitPath 一致：gitPath 为空时按 resourceName（manifest 里的 skill 名）在仓库内探测 SKILL.md。
 */
const ensureGitPathIfEmpty = async (
  params: ResolveSourceParams,
  type: ResourceType
): Promise<{ ok: true; params: ResolveSourceParams } | { ok: false; error: string }> => {
  const trimmed = (params.gitPath ?? '').trim();
  if (trimmed !== '') {
    return { ok: true, params: { ...params, gitPath: trimmed } };
  }

  if (type === 'skill') {
    const skillName = params.resourceName?.trim();
    if (!skillName) {
      return {
        ok: false,
        error:
          'gitPath is empty: set gitPath in ai-package.json, or use the skill key as the resource name for automatic discovery',
      };
    }
    const sha = extractSha(params.version);
    if (!sha) {
      return { ok: false, error: 'Cannot discover skill path: version is missing' };
    }
    const platform = params.source === SourceGit.Codebase ? 'codebase' : 'github';
    const d = await discoverSkillPath({
      owner: params.owner,
      repo: params.repo,
      sha,
      skillName,
      token: params.token,
      platform,
    });
    if (!d.success) return { ok: false, error: d.error };
    return { ok: true, params: { ...params, gitPath: d.gitPath } };
  }

  if (type === 'mcp' || type === 'plugin') {
    return { ok: true, params: { ...params, gitPath: '.' } };
  }

  return {
    ok: false,
    error: 'gitPath is empty: set gitPath in ai-package.json for this component',
  };
};

const resolveGitViaApi = async (
  params: ResolveSourceParams,
  token?: string
): Promise<ResolveSourceResult> => {
  const sha = extractSha(params.version);

  if (isFilePath(params.gitPath)) {
    const result = await fetchGitSingleFile({
      owner: params.owner,
      repo: params.repo,
      sha,
      filePath: params.gitPath,
      token,
    });
    if (!result.success || !result.file) {
      return { success: false, error: result.error };
    }
    return { success: true, files: [result.file] };
  }

  return await resolveGitViaClone(params, token);
};

const resolveGitViaClone = async (
  params: ResolveSourceParams,
  token?: string
): Promise<ResolveSourceResult> => {
  const sha = extractSha(params.version);
  return cloneAndRead({
    owner: params.owner,
    repo: params.repo,
    sha,
    targetPath: params.gitPath,
    token,
    platform: params.source === SourceGit.Codebase ? 'codebase' : 'github',
  });
};

/**
 * Resolve git-based sources: try API first, fallback to clone.
 */
const resolveGit = async (
  params: ResolveSourceParams,
  type: ResourceType
): Promise<ResolveSourceResult> => {
  const ensured = await ensureGitPathIfEmpty(params, type);
  if (!ensured.ok) return { success: false, error: ensured.error };
  const p = ensured.params;

  vlog(`[resolveSource] git: ${p.owner}/${p.repo}@${p.version} path="${p.gitPath}"`);
  const token = REDACTED(p);
  const apiResult = await resolveGitViaApi(p, token);
  if (apiResult.success) return apiResult;

  vlog('[resolveSource] API failed, fallback to clone');
  return await resolveGitViaClone(p, token);
};

const extractSkillName = (gitPath: string): string | undefined => {
  if (!gitPath || gitPath === '.') return undefined;
  const segments = gitPath.replace(/\/+$/, '').split('/');
  return segments[segments.length - 1] || undefined;
};

function resolveRegistryResourceName(params: ResolveSourceParams): string | undefined {
  if (params.resourceName?.trim()) return params.resourceName.trim();
  return extractSkillName(params.gitPath);
}

const zipFromBuffer = async (zipBuffer: ArrayBuffer): Promise<ResolveSourceResult> => {
  const zip = await JSZip.loadAsync(zipBuffer);
  const files: AiJsonFile[] = [];
  for (const [path, entry] of Object.entries(zip.files)) {
    if (entry.dir || path.includes('..')) continue;
    const content = await entry.async('string');
    files.push({ path, content });
  }

  if (files.length === 0) {
    return { success: false, error: 'Downloaded archive contained no files' };
  }

  return { success: true, files };
};

/**
 * When version is a semver and the marketplace has a matching row (any source),
 * download content.zip — faster than cloning git.
 */
const tryMarketplaceZip = async (
  params: ResolveSourceParams,
  type: 'skill' | 'mcp' | 'plugin'
): Promise<ResolveSourceResult | null> => {
  if (type !== 'skill' && type !== 'mcp' && type !== 'plugin') return null;
  if (isShaVersionString(params.version)) return null;

  const name = resolveRegistryResourceName(params);
  if (!name) return null;

  vlog(
    `[resolveSource] try marketplace zip: ${params.owner}/${params.repo} ${name}@${params.version}`
  );

  const dl = await downloadZip({
    type,
    owner: params.owner,
    repo: params.repo,
    name,
    version: params.version,
  });

  if (!dl.success || !dl.zipBuffer) {
    vlog('[resolveSource] marketplace zip miss:', dl.error ?? '');
    return null;
  }

  return zipFromBuffer(dl.zipBuffer);
};

const resolveRegistry = async (
  params: ResolveSourceParams,
  type: 'skill' | 'mcp' | 'command' | 'plugin'
): Promise<ResolveSourceResult> => {
  if (type === 'command') {
    return {
      success: false,
      error: `Registry download is not supported for type: ${type}`,
    };
  }

  const name = resolveRegistryResourceName(params);
  if (!name) {
    return { success: false, error: 'Could not derive resource name from gitPath' };
  }

  const dl = await downloadZip({
    source: params.source,
    owner: params.owner,
    repo: params.repo,
    type,
    name,
    version: params.version,
  });

  if (!dl.success || !dl.zipBuffer) {
    return { success: false, error: dl.error ?? 'Download failed' };
  }

  return zipFromBuffer(dl.zipBuffer);
};

export type ResolveSource = (
  params: ResolveSourceParams,
  type?: ResourceType
) => Promise<ResolveSourceResult>;

const resolveSource: ResolveSource = async (params, type = ResourceType.Skill) => {
  switch (params.source) {
    case SourceGit.GitHub:
    case SourceGit.Codebase: {
      const zipped = await tryMarketplaceZip(params, type);
      if (zipped?.success && zipped.files) return zipped;
      return resolveGit(params, type);
    }
    case SourceRegistry.Local:
    case SourceRegistry.Workspace:
      return resolveRegistry(params, type);
    default:
      return { success: false, error: `Unsupported source: ${params.source}` };
  }
};

export default resolveSource;

