  const paths: string[] = [];
  const seen = new Set<string>();
  for (const agent of agents) {
    const dir = getAgentDir({ agent: agent as Agent, base: GLOBAL_SENTINEL, capability: 'plugin' });
    if (!dir || seen.has(dir)) continue;
    seen.add(dir);

    const globalCfg =
      agent.pluginConfig && 'globalConfig' in agent.pluginConfig && agent.pluginConfig.globalConfig
        ? agent.pluginConfig.globalConfig
        : undefined;

    if (globalCfg?.marketplace) {
      // Marketplace layout: marketplacesDir/<mpName>/plugins/<name>/
