// ── Enums (single source of truth) ───────────────────

/** Git platforms — resolve content via git clone / API */
export enum SourceGit {
  GitHub = 'github',
  Codebase = 'codebase',
}

/** Registry sources — resolve content via marketplace zip download */
export enum SourceRegistry {
  Local = 'local',
  Workspace = 'workspace',
}

/** All source values including non-tracked 'origin' */
export enum Source {
  GitHub = 'github',
  Codebase = 'codebase',
  Local = 'local',
  Workspace = 'workspace',
  Origin = 'origin',
}

/** Resource types */
export enum ResourceType {
  Skill = 'skill',
  Mcp = 'mcp',
  Plugin = 'plugin',
}

// ── Derived types ────────────────────────────────────

/** Union of all tracked source values (excludes 'origin') */
export type AiJsonTrackedSource = SourceGit | SourceRegistry;

/** Union of registry source values only */
export type AiJsonRegistrySource = `${SourceRegistry}`;

/** Union of all source values */
export type AiJsonSource = `${Source}`;

/** Union of all resource type values */
export type AiJsonComponentType = `${ResourceType}`;

/**
 * @deprecated Alias — use {@link AiJsonTrackedSource}.
 */
export type AiJsonGitSource = AiJsonTrackedSource;

// ── Version ──────────────────────────────────────────

/** "sha@<hex>" for git platforms; semver for registry sources */
export type AiJsonVersion = string;

// ── Tracked entry ────────────────────────────────────

/**
 * Entry installed from a tracked source (github, codebase, local, workspace).
 *
 * - `owner` + `repo` identify the repository (or collection)
 * - `version` pins content: `sha@<hex>` for github/codebase, semver for local/workspace
 * - `gitPath` 为仓库内相对路径；可为空字符串，安装时按 skill 名对仓库做路径探测（见 resolveSource）
 */
export type AiJsonGitTrackedEntry = {
  source: AiJsonTrackedSource;
  owner: string;
  repo: string;
  version: AiJsonVersion;
  gitPath: string;
  /** Branch or tag; omitted when installed from the default branch */
  branch?: string;
};

/**
 * @deprecated Use {@link AiJsonGitTrackedEntry} instead.
 */
export type AiJsonComponentEntry = AiJsonGitTrackedEntry;

// ── Special source entries ───────────────────────────

/** Project-original content, not version-tracked */
export type AiJsonOriginEntry = {
  source: Source.Origin;
  /**
   * Directory or `.zip` path for this item.
   * Project manifest: path relative to the `ai-package.json` directory when under project root; otherwise absolute.
   * Global manifest: absolute path.
