const buildCachePath = (
  source: string,
  owner: string,
  repo: string,
  version: string,
  name: string
): string => {
  const cacheRoot = getEnv({ key: 'cache' });
  const safeVersion = version.replace(/[/:*?"<>|]/g, '_');
  return join(cacheRoot, source, owner, repo, safeVersion, 'plugin', name);
};

/**
 * Find the parent dir of plugin.json whose `name` field matches `pluginName`,
 * regardless of what the directory is called.
 */
function findPluginJsonParentDir(
  files: Array<{ path: string; content: string }>,
  pluginName: string
): string | undefined {
  for (const f of files) {
    if (!f.path.endsWith('/plugin.json') && f.path !== 'plugin.json') continue;
    try {
      const parsed = JSON.parse(f.content);
      if (parsed.name === pluginName) {
        const slash = f.path.lastIndexOf('/');
        return slash === -1 ? undefined : f.path.slice(0, slash);
      }
    } catch {
      // ignore malformed json
    }
  }
  return undefined;
}

function renameParentDir(
  files: Array<{ path: string; content: string }>,
  sourceDir: string,
  targetDir: string
): Array<{ path: string; content: string }> {
  if (sourceDir === targetDir) return files;
  const prefix = new RegExp(`^${sourceDir.replace(/[.*+?^${}()|[\]\\]/g, '\\$&')}(?=/|$)`);
  return files.map((f) => {
    if (f.path === sourceDir || f.path.startsWith(`${sourceDir}/`)) {
      return { ...f, path: f.path.replace(prefix, targetDir) };
    }
    return f;
  });
}

/** Plugin bundle only: `agentList.pluginBundleMcpFileTransform` (not project `mcpConfig`). */
function applyPluginBundleMcpFileTransform(
  files: AiJsonFile[],
  transform: PluginBundleMcpFileTransform
): AiJsonFile[] {
  const from = transform.renameFile.fromBasename;
  const to = transform.renameFile.toBasename;
  const unwrap = transform.unwrapRootKey;

  return files.map((f) => {
    const norm = f.path.replace(/\\/g, '/');
    const seg = norm.split('/');
    if (seg[seg.length - 1] !== from) return f;

    let content = f.content;
    if (unwrap) {
      try {
        const data = JSON.parse(content) as Record<string, unknown>;
        const inner = data[unwrap];
        if (inner && typeof inner === 'object' && !Array.isArray(inner)) {
          content = JSON.stringify(inner, null, 2);
        }
      } catch {
        // keep raw content
      }
    }
    seg[seg.length - 1] = to;
    return { path: seg.join('/'), content };
  });
}

// ── Marketplace helpers ──────────────────────────────

function readJsonSafe<T = unknown>(filePath: string): T | null {
  if (!existsSync(filePath)) return null;
  try {
    return JSON.parse(readFileSync(filePath, 'utf-8')) as T;
  } catch {
    return null;
  }
}

function writeJsonAtomic(filePath: string, data: unknown): void {
  mkdirSync(dirname(filePath), { recursive: true });
  writeFileSync(filePath, JSON.stringify(data, null, 2));
}

function updateKnownMarketplaces(mp: PluginMarketplaceConfig, manifestDir: string): void {
  const filePath = mp.knownMarketplacesFile({ home });
  const known = readJsonSafe<Record<string, unknown>>(filePath) ?? {};

  if (known[mp.name]) {
    vlog(`[installPlugin] marketplace "${mp.name}" already registered`);
    return;
  }

  known[mp.name] = {
    source: { source: 'directory', path: manifestDir },
    installLocation: manifestDir,
    lastUpdated: new Date().toISOString(),
  };

  writeJsonAtomic(filePath, known);
  vlog(`[installPlugin] registered marketplace "${mp.name}"`);
}

/**
 * Generate <pluginConfigFileDir>/marketplace.json inside the marketplace manifest directory.
 * Claude Code requires this file to recognise the marketplace.
 */
function writeMarketplaceManifest(
  manifestDir: string,
  pluginConfigFileDir: string,
  mp: PluginMarketplaceConfig,
  pluginName: string,
  pluginVersion: string
): void {
  const cfgDir = join(manifestDir, pluginConfigFileDir);
  const manifestPath = join(cfgDir, 'marketplace.json');

  const existing = existsSync(manifestPath)
    ? readJsonSafe<{ name?: string; owner?: unknown; plugins?: unknown[] }>(manifestPath)
    : null;

  const plugins = Array.isArray(existing?.plugins) ? [...existing.plugins] : [];
  const newSource = `./plugins/${pluginName}/${pluginVersion}`;
  const existingIdx = plugins.findIndex(
    (p) => typeof p === 'object' && p !== null && (p as Record<string, unknown>).name === pluginName
  );
  if (existingIdx === -1) {
    plugins.push({
      name: pluginName,
      source: newSource,
      description: '',
    });
  } else {
    const prev = plugins[existingIdx] as Record<string, unknown>;
    plugins[existingIdx] = {
      ...prev,
      name: pluginName,
      source: newSource,
    };
  }

  const manifest = {
    name: existing?.name ?? mp.name,
    owner: existing?.owner ?? { name: 'plugins' },
    plugins,
  };

  mkdirSync(cfgDir, { recursive: true });
  writeFileSync(manifestPath, JSON.stringify(manifest, null, 2));
  vlog(`[installPlugin] wrote ${pluginConfigFileDir}/marketplace.json in ${manifestDir}`);
}

type InstalledPluginsData = {
  version: number;
  plugins: Record<string, unknown[]>;
};

function updateInstalledPlugins(
  mp: PluginMarketplaceConfig,
  pluginName: string,
  installPath: string,
  version: string
): void {
  const filePath = mp.installedPluginsFile({ home });
  const data = readJsonSafe<InstalledPluginsData>(filePath) ?? { version: 2, plugins: {} };
  if (!data.plugins) data.plugins = {};

  const pluginKey = `${pluginName}@${mp.name}`;
  const now = new Date().toISOString();
  data.plugins[pluginKey] = [
    {
      scope: 'user',
      installPath,
      version,
      installedAt: now,
      lastUpdated: now,
    },
  ];

  writeJsonAtomic(filePath, data);
  vlog(`[installPlugin] recorded install "${pluginKey}" in installed_plugins.json`);
}

function updateEnabledPlugins(
  mp: PluginMarketplaceConfig,
  pluginName: string,
  projectRoot?: string
): void {
  const filePath =
    projectRoot && mp.projectEnabledPluginsFile
      ? join(projectRoot, mp.projectEnabledPluginsFile)
      : mp.enabledPluginsFile({ home });

  const data = readJsonSafe<Record<string, unknown>>(filePath) ?? {};

  const key = mp.enabledPluginsKey;
  const enabled =
    typeof data[key] === 'object' && data[key] !== null
      ? { ...(data[key] as Record<string, unknown>) }
      : {};

  const pluginKey = `${pluginName}@${mp.name}`;
  enabled[pluginKey] = true;
  data[key] = enabled;

  writeJsonAtomic(filePath, data);
  vlog(`[installPlugin] enabled "${pluginKey}" in ${filePath}`);
}

function updateFlatEnablement(
  enablement: PluginFlatEnablementConfig,
  pluginName: string,
  projectRoot: string
): void {
  const filePath = join(projectRoot, enablement.settingsFile);
  const data = readJsonSafe<Record<string, unknown>>(filePath) ?? {};

  const section =
    typeof data[enablement.settingsKey] === 'object' && data[enablement.settingsKey] !== null
      ? { ...(data[enablement.settingsKey] as Record<string, unknown>) }
