  const entryKey = enablement.keySuffix ? `${pluginName}${enablement.keySuffix}` : pluginName;
  section[entryKey] = enablement.entryValue;
  data[enablement.settingsKey] = section;

  writeJsonAtomic(filePath, data);
  vlog(`[installPlugin] enabled "${entryKey}" in ${filePath}`);
}

