import type { Agent, McpAgent, PluginAgent, SkillAgent } from '@/types';
import getConfig from '../../config/getConfig';
import getDetectedAgents from '../getDetectedAgents';
import resolveAgentsName from '../resolveAgentsName';

export type ResolveAgentsOptions = {
  agents?: string;
};

export type ResolveAgentsParams = {
  opts: ResolveAgentsOptions;
  capability: 'skill' | 'mcp' | 'plugin';
  /** When provided, excludes agents whose config for the capability doesn't support this scope. */
  scope?: 'project' | 'global';
};

export type ResolveAgentsResult = {
  agents: Array<Agent>;
  defaultSelected: Array<Agent>;
  unrecognized: Array<string>;
  needsInteraction: boolean;
  skipInteraction: boolean;
};

export type ResolveAgents = (params: ResolveAgentsParams) => ResolveAgentsResult;

function isScopeCompatible(
  agent: Agent,
  capability: 'skill' | 'mcp' | 'plugin',
  scope: 'project' | 'global'
): boolean {
  if (capability === 'mcp' && agent.mcp) {
    const cfg = (agent as McpAgent).mcpConfig;
    if (scope === 'project' && 'globalOnly' in cfg && cfg.globalOnly) return false;
    if (scope === 'global' && 'projectOnly' in cfg && cfg.projectOnly) return false;
  }
  if (capability === 'skill' && agent.skill) {
    const dirs = (agent as SkillAgent).skillDirs;
    if (scope === 'project' && 'globalOnly' in dirs && dirs.globalOnly) return false;
    if (scope === 'global' && 'projectOnly' in dirs && dirs.projectOnly) return false;
  }
  if (capability === 'plugin' && agent.plugin) {
    const cfg = (agent as PluginAgent).pluginConfig;
    if (scope === 'project' && 'globalOnly' in cfg && cfg.globalOnly) return false;
    if (scope === 'global' && 'projectOnly' in cfg && cfg.projectOnly) return false;
  }
  return true;
}

const resolveAgents: ResolveAgents = ({ opts, capability, scope }) => {
  const config = getConfig();
  const defaultSelectConfig = config.agent.defaultSelect[capability];
  const skipConfig = config.agent.skip[capability];

  const scopeFilter = (a: Agent) => !scope || isScopeCompatible(a, capability, scope);

  if (opts.agents) {
    const result = resolveAgentsName({ agentsName: opts.agents, excludeModeOn: true });
    const capable = result.resolved.filter((a) => a[capability] === true).filter(scopeFilter);
    return {
      agents: capable,
      defaultSelected: capable,
      unrecognized: result.unrecognized,
      needsInteraction: false,
      skipInteraction: true,
    };
  }

  const detected = getDetectedAgents({ capability }).filter(scopeFilter);

  let defaultSelected: Agent[];
  if (defaultSelectConfig === 'all') {
    defaultSelected = [...detected];
  } else if (defaultSelectConfig === 'none') {
    defaultSelected = [];
  } else if (Array.isArray(defaultSelectConfig)) {
    const selectResult = resolveAgentsName({
      agentsName: (defaultSelectConfig as string[]).join(' '),
      excludeModeOn: false,
    });
    const capableSelected = selectResult.resolved
      .filter((a) => a[capability] === true)
      .filter(scopeFilter);
    for (const a of capableSelected) {
      if (!detected.some((d) => d.name === a.name)) detected.push(a);
    }
    defaultSelected = capableSelected;
  } else {
    defaultSelected = [];
  }

  const needsInteraction = !skipConfig;

  return {
    agents: detected,
    defaultSelected,
    unrecognized: [],
    needsInteraction,
    skipInteraction: skipConfig,
  };
};

export default resolveAgents;

