import { mkdirSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import getConfig from '@/core/config/getConfig';
import getEnv from '@/core/config/getEnv';
import { GLOBAL_SENTINEL } from '../getAgentDir';

export type InstallScopeCliOptions = {
  project?: boolean;
  global?: boolean;
  target?: string;
  dir?: string;
};

export type InstallContextMode = 'direct' | 'targetBase' | 'global' | 'project';

export type InstallContext = {
  mode: InstallContextMode;
  /** Base path for getAgentDir (skill/MCP project layout), or GLOBAL_SENTINEL */
  skillBase: string;
  mcpBase: string;
  mcpScope: 'project' | 'global';
  /** Parent directory of ai-package.json; only meaningful when skipAiJson is false */
  aiJsonDir: string;
  /** When true, -t/--dir modes should NOT read/write ai-package.json */
  skipAiJson: boolean;
  /** Resolved absolute parent of skill folders when mode === direct */
  directSkillParentDir?: string;
  skipAgentSelection: boolean;
};

export type ResolveInstallContextResult =
  | { ok: true; context: InstallContext }
  | {
      ok: false;
      code: 'CONFLICTING_FLAGS' | 'NEED_SCOPE' | 'INVALID_PATH';
      message: string;
    };

export type ResolveInstallContextParams = {
  opts: InstallScopeCliOptions;
  /** Override config (tests); default reads install.defaultScope */
  defaultScope?: 'select' | 'project' | 'global';
};

/** Parent directory containing global ai-package.json (from install.global_ai_json / env). */
export const getGlobalAiJsonDir = (): string => {
  const filePath = resolve(getEnv({ key: 'globalAiJson' }));
  return dirname(filePath);
};

const hasExplicitScope = (o: InstallScopeCliOptions): boolean =>
  Boolean(o.dir || o.target || o.global || o.project);

/**
 * Resolves install scope: --dir > -t > -g > -p > install.defaultScope (when not select).
 * Creates directories as needed for target base, direct parent, and global ai-package.json parent.
 */
const resolveInstallContext = (
  params: ResolveInstallContextParams
): ResolveInstallContextResult => {
  const { opts } = params;
  const defaultScope = params.defaultScope ?? getConfig().install.default_scope;

  const cwd = process.cwd();

  if (opts.project && opts.global && !opts.target && !opts.dir) {
    return {
      ok: false,
      code: 'CONFLICTING_FLAGS',
      message: 'Cannot use both --project and --global',
    };
  }

  if (opts.dir) {
    try {
      const abs = resolve(opts.dir);
      mkdirSync(abs, { recursive: true });
      return {
        ok: true,
        context: {
          mode: 'direct',
          skillBase: cwd,
          mcpBase: cwd,
          mcpScope: 'project',
          aiJsonDir: cwd,
          skipAiJson: true,
          directSkillParentDir: abs,
          skipAgentSelection: true,
        },
      };
    } catch (e) {
      return {
        ok: false,
        code: 'INVALID_PATH',
        message: `Invalid --dir: ${String(e)}`,
      };
    }
  }

  if (opts.target) {
    try {
      const base = resolve(opts.target);
      mkdirSync(base, { recursive: true });
      return {
        ok: true,
        context: {
          mode: 'targetBase',
          skillBase: base,
          mcpBase: base,
          mcpScope: 'project',
          aiJsonDir: base,
          skipAiJson: false,
          skipAgentSelection: false,
        },
      };
    } catch (e) {
      return {
        ok: false,
        code: 'INVALID_PATH',
        message: `Invalid --target: ${String(e)}`,
      };
    }
  }

  if (opts.global) {
    try {
      const aiJsonDir = getGlobalAiJsonDir();
      mkdirSync(aiJsonDir, { recursive: true });
      return {
        ok: true,
        context: {
          mode: 'global',
          skillBase: GLOBAL_SENTINEL,
          mcpBase: GLOBAL_SENTINEL,
          mcpScope: 'global',
          aiJsonDir,
          skipAiJson: false,
          skipAgentSelection: false,
        },
      };
    } catch (e) {
      return {
        ok: false,
        code: 'INVALID_PATH',
        message: `Invalid global ai-package.json path: ${String(e)}`,
      };
    }
  }

  if (opts.project) {
    return {
      ok: true,
      context: {
        mode: 'project',
        skillBase: cwd,
        mcpBase: cwd,
        mcpScope: 'project',
        aiJsonDir: cwd,
        skipAiJson: false,
        skipAgentSelection: false,
      },
    };
  }

  if (!hasExplicitScope(opts)) {
    if (defaultScope === 'select') {
      return {
        ok: false,
        code: 'NEED_SCOPE',
        message:
          'Install scope not specified: use -p, -g, -t, or --dir, or set install.default_scope to project/global',
      };
    }
    if (defaultScope === 'global') {
      try {
        const aiJsonDir = getGlobalAiJsonDir();
        mkdirSync(aiJsonDir, { recursive: true });
        return {
          ok: true,
          context: {
            mode: 'global',
            skillBase: GLOBAL_SENTINEL,
            mcpBase: GLOBAL_SENTINEL,
            mcpScope: 'global',
            aiJsonDir,
            skipAiJson: false,
            skipAgentSelection: false,
          },
        };
      } catch (e) {
        return {
          ok: false,
          code: 'INVALID_PATH',
          message: `Invalid global ai-package.json path: ${String(e)}`,
        };
      }
    }
  }

  return {
    ok: true,
    context: {
      mode: 'project',
      skillBase: cwd,
      mcpBase: cwd,
      mcpScope: 'project',
      aiJsonDir: cwd,
      skipAiJson: false,
      skipAgentSelection: false,
    },
  };
};

export type ResolveInstallContext = typeof resolveInstallContext;

/** Maps resolved install context to skill scan / ai-package.json paths. */
export type SkillScopeScanParams = {
  isDirMode: boolean;
  scanBase: string;
  scanDir: string | undefined;

