// ── MCP config types ─────────────────────────────────

export type McpConfigFormat = 'json' | 'toml' | 'yaml';

/**
 * 'map' (default): servers stored as `{ [name]: config }` objects.
 * 'array': servers stored as `[{ name, ...config }]` arrays (e.g. Trae CLI yaml).
 */
export type McpServerStructure = 'map' | 'array';

export type McpProjectConfigSpec = {
  filePath: string;
  format: McpConfigFormat;
  /** Key in the config file where MCP servers live (e.g. "mcpServers", "servers", "mcp_servers") */
  rootKey: string;
  /** Whether entries need a "type" field (e.g. vscode needs { type: "http", url }) */
  entryNeedsType: boolean;
  /** How servers are stored under rootKey. Defaults to 'map'. */
  serverStructure?: McpServerStructure;
};

export type McpGlobalConfigSpec = {
  filePath: (params: { home: string }) => string;
